local gg_original = gg
local NOME_NOVO = "ThanosCraft Script v1.0"

gg = setmetatable({}, {
    __index = function(tabela, chave)
        local valor_original = gg_original[chave]

        -- Intercepta as funções de menu apenas para alterar o título
        if chave == "choice" or chave == "multiChoice" then
            return function(items, default, title, ...)
                local novo_title = title
                
                if type(title) == "string" and title:find("IGG CHEAT GAME") then
                    novo_title = title:gsub("IGG CHEAT GAME", NOME_NOVO)
                end
                
                -- Executa o menu original apenas com o título trocado
                return valor_original(items, default, novo_title, ...)
            end
        end

        return valor_original
    end
})

